import{_ as r,C as o,o as n,c as i,ai as a,E as s,w as l,a as d}from"./chunks/framework.BH_J6TYN.js";const _=JSON.parse('{"title":"QR y sticker","description":"Descarga el código QR de tu negocio para imprimir y compartir","frontmatter":{"title":"QR y sticker","description":"Descarga el código QR de tu negocio para imprimir y compartir"},"headers":[],"relativePath":"studio/qr-sticker.md","filePath":"studio/qr-sticker.md"}'),c={name:"studio/qr-sticker.md"};function p(u,e,m,h,g,b){const t=o("Tip");return n(),i("div",null,[e[1]||(e[1]=a('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El QR de SYNTIweb es un código QR descargable que al escanearlo lleva directamente a tu página web (<code>tunegocio.syntiweb.com</code>). Es ideal para imprimir en carteleras, menús, tarjetas de presentación o pegarlo en la puerta de tu local.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p>El QR se genera automáticamente al crear tu negocio. Para descargarlo:</p><p><strong>Tu panel → Configuración</strong> → Verás tu QR con opciones de descarga.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Genera un QR único</strong> con la URL de tu negocio</li><li><strong>Incluye tracking</strong> — cada escaneo se registra en tus analíticas</li><li><strong>Descargable en alta resolución</strong> para imprimir</li><li><strong>Shortlink asociado</strong> — URL corta que también puedes compartir</li></ul><h2 id="donde-poner-el-qr" tabindex="-1">Dónde poner el QR <a class="header-anchor" href="#donde-poner-el-qr" aria-label="Permalink to &quot;Dónde poner el QR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dónde</th><th>Tamaño recomendado</th></tr></thead><tbody><tr><td><strong>Puerta del local</strong></td><td>5×5 cm o más</td></tr><tr><td><strong>Empaques y bolsas</strong></td><td>3×3 cm</td></tr><tr><td><strong>Mesas del local</strong></td><td>Laminado para protegerlo</td></tr><tr><td><strong>Tarjetas de presentación</strong></td><td>Mínimo 3×3 cm</td></tr><tr><td><strong>Cartelera / banner</strong></td><td>10×10 cm o más</td></tr><tr><td><strong>WhatsApp (estado)</strong></td><td>Comparte la imagen del QR</td></tr></tbody></table>',9)),s(t,null,{default:l(()=>[...e[0]||(e[0]=[d(" Imprime el QR en tamaño mínimo de **3×3 centímetros** para asegurar que sea escaneable. Cualquier tamaño menor puede dar problemas con cámaras de baja resolución. ",-1)])]),_:1}),e[2]||(e[2]=a('<h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><p>El QR, el shortlink y las analíticas de escaneos están disponibles en <strong>todos los planes</strong> (Oportunidad, Crecimiento y Visión).</p><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-arepera-la-reina-del-maiz-en-caracas" tabindex="-1">Caso: Arepera &quot;La Reina del Maíz&quot; en Caracas <a class="header-anchor" href="#caso-arepera-la-reina-del-maiz-en-caracas" aria-label="Permalink to &quot;Caso: Arepera &quot;La Reina del Maíz&quot; en Caracas&quot;">​</a></h3><p>Martha tiene una arepera. Descarga su QR desde el panel e imprime 50 stickers de 5×5 cm. Los pega en la puerta de entrada, cada embalaje de delivery, las mesas del local y su tarjeta de presentación.</p><p>Cuando un cliente escanea el QR, llega a <code>lareinadelmaiz.syntiweb.com</code> donde ve el menú con precios actualizados. Martha chequea en <strong>Pulso del Negocio</strong> cuántos escaneos recibe por día.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/shared/dominio-y-subdominio.html">Tu dirección web</a> — Cómo funciona tu subdominio</li><li><a href="/studio/seo-automatico.html">SEO automático</a> — Cómo tu negocio aparece en Google</li><li><a href="/studio/seccion-config.html">Configuración</a> — Dónde encontrar el QR en tu panel</li></ul>',8))])}const f=r(c,[["render",p]]);export{_ as __pageData,f as default};
